module RefModule(
    input in0, in1, in2, in3, clk, reset,
    input d0, d1, d2, d3,
    output reg out0, out1, out2, out3
);reg [3:0] unused_out_reg;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        unused_out_reg <= 4'b0;
    end else begin
        unused_out_reg[0] <= in0 ? d0 : unused_out_reg[0];
        unused_out_reg[1] <= in1 ? d1 : unused_out_reg[1];
        unused_out_reg[2] <= in2 ? d2 : unused_out_reg[2];
        unused_out_reg[3] <= in3 ? d3 : unused_out_reg[3];
    end
end

assign out0 = unused_out_reg[0];
assign out1 = unused_out_reg[1];
assign out2 = unused_out_reg[2];
assign out3 = unused_out_reg[3];

endmodule
